      target_model: target,
      every_n_turns: Math.max(1, toInt(normalized.every_n_turns, 1)),
      read_dialogue_rounds: Math.max(
        0,
        toInt(normalized.read_dialogue_rounds, 4),
      ),
      read_lorebook_names: normalizeCommaList(normalized.read_lorebook_names),
