  async function readPluginStorageJson(key, fallback = null) {
    try {
      const raw = await Risuai.pluginStorage.getItem(key);
      if (raw === null || raw === undefined || raw === "") return fallback;
      if (typeof raw === "string") return JSON.parse(raw);
      return raw;
    } catch {
      return fallback;
    }
  }
