      memrlMode: v('memrlMode'),
      keywordExtractionMode: v('keywordExtractionMode', trimStr),
      useGliner: v('useGliner', b => b === true || b === 'true'),
      rerankerEndpoint: v('rerankerEndpoint', trimStr),
      rerankerModel: v('rerankerModel', trimStr),
      rerankerApiKey: v('rerankerApiKey', trimStr),
      vertexAiServiceAccountJson: v('vertexAiServiceAccountJson', trimStr),
      relationshipWeights: v('relationshipWeights'),
